<?php require __DIR__.'/auth.php'; require_admin(); require __DIR__.'/_layout.php'; $pages=read_json('pages_seo',[]); admin_header('Admin — SEO des pages','seo'); ?><div class="admin-top"><div><h1>SEO des pages</h1><p>Gérez le référencement et les métadonnées de toutes les pages du site.</p></div><button form="seoForm" class="btn btn-primary" type="submit">Enregistrer</button></div><?php if(isset($_GET['saved'])): ?><div class="notice">SEO enregistré.</div><?php endif; ?><form id="seoForm" method="post" action="/admin/seo-save.php" class="admin-panel"><?= csrf_field() ?><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>Page</th><th>Meta title</th><th>Meta description</th><th>H1</th><th>Slug</th><th>Canonical</th><th>Mots-clés</th><th>Open Graph</th></tr></thead><tbody><?php foreach($pages as $i=>$p): ?><tr><td><input type="hidden" name="pages[<?= $i ?>][key]" value="<?= e($p['key']??'') ?>"><input name="pages[<?= $i ?>][page]" value="<?= e($p['page']??'') ?>"></td><td><textarea name="pages[<?= $i ?>][meta_title]"><?= e($p['meta_title']??'') ?></textarea></td><td><textarea name="pages[<?= $i ?>][meta_description]"><?= e($p['meta_description']??'') ?></textarea></td><td><textarea name="pages[<?= $i ?>][h1]"><?= e($p['h1']??'') ?></textarea></td><td><input name="pages[<?= $i ?>][slug]" value="<?= e($p['slug']??'') ?>"></td><td><textarea name="pages[<?= $i ?>][canonical]"><?= e($p['canonical']??'') ?></textarea></td><td><textarea name="pages[<?= $i ?>][keywords]"><?= e($p['keywords']??'') ?></textarea></td><td><input name="pages[<?= $i ?>][og_image]" value="<?= e($p['og_image']??'') ?>"></td></tr><?php endforeach; ?></tbody></table></div></form><?php admin_footer(); ?>
